INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (0, "オラの食材とあんちゃんの腕……\nこれは二人の共同作業ってことに……\nな、なんでもねぇ！\n気にしねぇでけろ！", 1, 103311, "", 5, 1033501, 1033501043, 0, 1, 11);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES ("", "", "", 0, "", "", 1033501, 1033501044, "", "", 91);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES ("", "vo_adv_1033501_002", 0, "vo_adv_1033501", "", 0, 1033501, 1033501045, "", "", 21);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (0, "それにしても食べるのが\nもったいねぇいいケーキだなぁ……\nでも食べなきゃ食べねぇで\nもったいねぇよなぁ……", 1, 103311, "", 6, 1033501, 1033501046, 0, 1, 11);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES ("", "", "", 0, "", "", 1033501, 1033501047, "", "", 91);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES ("", "vo_adv_1033501_003", 0, "vo_adv_1033501", "", 0, 1033501, 1033501048, "", "", 21);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (0, "うーん……\nオラ一人で食べるのも申し訳ねぇし\nエリザベスパークのみんなで\n食べるべか！", 1, 103311, "", 6, 1033501, 1033501049, 0, 1, 11);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES ("", "", "", 0, "", "", 1033501, 1033501050, "", "", 91);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES ("", "vo_adv_1033501_004", 0, "vo_adv_1033501", "", 0, 1033501, 1033501051, "", "", 21);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (0, "みんなで過ごすのがオラにとって\n最高の誕生日だべ！\nあんがとな、あんちゃん！", 1, 103311, "", 6, 1033501, 1033501052, 0, 1, 11);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES ("", "", "", 0, "", "", 1033501, 1033501053, "", "", 91);
