INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (0, "にゃはは～！\n誕生日のお祝いしてくれて\nどうもありがとにゃ！", 1, 104611, "", 6, 1046501, 1046501040, 0, 1, 11);
