INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (0, "誕生日を祝ってくれてありがとう。\nいくつになってもお祝いして\nもらえるのはうれしいものね。", 1, 105111, "", 7, 1051501, 1051501040, 0, 1, 11);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES ("", "", "", 0, "", "", 1051501, 1051501041, "", "", 91);
